import './App.css';
import Navbar from './components/ui/navbar';

function Map() {
  return (
    <div style={{ width: "100%", height: "100%" }}>
      <iframe
        src="https://www.google.com/maps/embed?pb=!1m14!1m12!1m3!1d39448.509951781474!2d-80.52416504530215!3d43.46217509205705!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!5e1!3m2!1sen!2sca!4v1757886417107!5m2!1sen!2sca"
        width="100%"
        height="100%"
        style={{ border: 0 }}
        allowFullScreen
        loading="lazy"
        referrerPolicy="no-referrer-when-downgrade"
        title="Google Map"
      ></iframe>
    </div>
  );
}

function App() {
  return (
    <div className="App">
      <Navbar />
      <div style={{ display: "flex", height: "calc(100vh - 60px)" }}>
        <div style={{ flex: 3 }}>
          <Map />
        </div>

        <div style={{ flex: 1, backgroundColor: "#f0f0f0", padding: "1rem" }}>
          <h2>Explore</h2>
          <p>Dietary Options:</p>

          <input type="radio" id="html" name="fav_language" value="HTML" />
          <label htmlFor="html">Vegetarian</label><br />
        </div>
      </div>
    </div>
  );
}

export default App;
